diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..f0da96da39a3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2719,6 +2719,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   // Note: We don't generate the inverse max/min, just create the 'not' of
   // it and let other folds do the rest.
   if (match(Op0, m_Not(m_Value(X))) &&
+
       match(Op1, m_c_MaxOrMin(m_Specific(Op0), m_Value(Y))) &&
       !Op0->hasNUsesOrMore(3) && isFreeToInvert(Y, Y->hasOneUse())) {
     Value *Not = Builder.CreateNot(Op1);
@@ -2869,6 +2870,75 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     }
   }

+  // min(X+1, Y) - min(X, Y) --> Y > X ? 1 : 0
+  // smin(X+1, Y) - smin(X, Y) --> select(icmp slt(X, Y), 1, 0)
+  {
+    Value *X, *Y, *A;
+    if (match(Op0, m_OneUse(m_c_SMin(m_Value(A), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_SMin(m_Value(X), m_Specific(Y)))) &&
+        match(A, m_NSWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpSLT(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // smin(X, Y) - smin(X+1, Y) --> select(icmp slt(X, Y), -1, 0)
+    if (match(Op0, m_OneUse(m_c_SMin(m_Value(X), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_SMin(m_Value(A), m_Specific(Y)))) &&
+        match(A, m_NSWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpSLT(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::getAllOnesValue(Ty),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // smax(X+1, Y) - smax(X, Y) --> select(icmp sge(X, Y), 1, 0)
+    if (match(Op0, m_OneUse(m_c_SMax(m_Value(A), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_SMax(m_Value(X), m_Specific(Y)))) &&
+        match(A, m_NSWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpSGE(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // smax(X, Y) - smax(X+1, Y) --> select(icmp sge(X, Y), -1, 0)
+    if (match(Op0, m_OneUse(m_c_SMax(m_Value(X), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_SMax(m_Value(A), m_Specific(Y)))) &&
+        match(A, m_NSWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpSGE(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::getAllOnesValue(Ty),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // umin(X+1, Y) - umin(X, Y) --> select(icmp ult(X, Y), 1, 0)
+    if (match(Op0, m_OneUse(m_c_UMin(m_Value(A), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_UMin(m_Value(X), m_Specific(Y)))) &&
+        match(A, m_NUWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpULT(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // umin(X, Y) - umin(X+1, Y) --> select(icmp ult(X, Y), -1, 0)
+    if (match(Op0, m_OneUse(m_c_UMin(m_Value(X), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_UMin(m_Value(A), m_Specific(Y)))) &&
+        match(A, m_NUWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpULT(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::getAllOnesValue(Ty),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // umax(X+1, Y) - umax(X, Y) --> select(icmp uge(X, Y), 1, 0)
+    if (match(Op0, m_OneUse(m_c_UMax(m_Value(A), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_UMax(m_Value(X), m_Specific(Y)))) &&
+        match(A, m_NUWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpUGE(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::getNullValue(Ty));
+    }
+    // umax(X, Y) - umax(X+1, Y) --> select(icmp uge(X, Y), -1, 0)
+    if (match(Op0, m_OneUse(m_c_UMax(m_Value(X), m_Value(Y)))) &&
+        match(Op1, m_OneUse(m_c_UMax(m_Value(A), m_Specific(Y)))) &&
+        match(A, m_NUWAdd(m_Specific(X), m_One()))) {
+      Value *Cmp = Builder.CreateICmpUGE(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::getAllOnesValue(Ty),
+                                ConstantInt::getNullValue(Ty));
+    }
+  }
+
   if (Instruction *Res = foldBinOpOfSelectAndCastOfSelectCondition(I))
     return Res;

@@ -2920,6 +2990,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
 /// This eliminates floating-point negation in either 'fneg(X)' or
 /// 'fsub(-0.0, X)' form by combining into a constant operand.
 static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {

